using Autodesk.AutoCAD.ApplicationServices;using Autodesk.AutoCAD.Colors;using Autodesk.AutoCAD.DatabaseServices;using Autodesk.AutoCAD.EditorInput;using Autodesk.AutoCAD.Runtime;using System;using System.Linq;
namespace Tgirrr.CadLisp {public sealed class DripLayoutCommands {[CommandMethod("VDNG")]public void Run(){var doc=Application.DocumentManager.MdiActiveDocument;var ed=doc.Editor;var filter=new SelectionFilter(new[]{new TypedValue(0,"LWPOLYLINE,CIRCLE")});var selection=ed.GetSelection(new PromptSelectionOptions{MessageForAdding="\nChọn một hoặc nhiều Boundary kín: "},filter);if(selection.Status!=PromptStatus.OK)return;var window=new DripLayoutWindow(doc.Database.Insunits);if(Application.ShowModalWindow(window)!=true)return;int boundaries=0,skipped=0,lines=0;using(doc.LockDocument())using(var tr=doc.TransactionManager.StartTransaction()){var db=doc.Database;var lt=(LayerTable)tr.GetObject(db.LayerTableId,OpenMode.ForRead);ObjectId layerId;if(!lt.Has("TG-DRIP")){lt.UpgradeOpen();var layer=new LayerTableRecord{Name="TG-DRIP",Color=Color.FromColorIndex(ColorMethod.ByAci,34)};layerId=lt.Add(layer);tr.AddNewlyCreatedDBObject(layer,true);}else layerId=lt["TG-DRIP"];var space=(BlockTableRecord)tr.GetObject(db.CurrentSpaceId,OpenMode.ForWrite);foreach(var id in selection.Value.GetObjectIds()){var entity=tr.GetObject(id,OpenMode.ForRead)as Entity;Polyline p=entity as Polyline;bool temporary=false;if(entity is Circle circle){p=CircleBoundary(circle);temporary=true;}if(p!=null&&!temporary&&!p.Closed&&p.NumberOfVertices>=3){p.UpgradeOpen();p.Closed=true;ed.WriteMessage("\nVDNG: Đã tự đóng Boundary "+id.Handle+" (nối điểm cuối về điểm đầu).");}if(p==null||!p.Closed||p.NumberOfVertices<3){ed.WriteMessage("\nVDNG: Boundary "+id.Handle+" không hợp lệ — loại="+(entity?.GetType().Name??"null")+", Closed="+(p!=null&&p.Closed)+", số đỉnh="+(p?.NumberOfVertices??0)+".");if(temporary)p?.Dispose();skipped++;continue;}try{var direction=DripLayoutService.Direction(p);var regions=DripLayoutService.Inner(p,window.Inset);if(regions.Count==0){skipped++;ed.WriteMessage("\nVDNG: Boundary "+id.Handle+" không tạo được offset phía trong (khoảng lùi="+window.Inset+", diện tích="+Math.Abs(p.Area)+"). Hãy giảm khoảng lùi hoặc kiểm tra Polyline tự giao/cạnh quá ngắn.");if(temporary)p.Dispose();continue;}foreach(Polyline region in regions){foreach(var segment in DripLayoutService.Fill(region,window.Spacing,direction)){var line=new Polyline(2);line.AddVertexAt(0,new Autodesk.AutoCAD.Geometry.Point2d(segment.StartPoint.X,segment.StartPoint.Y),0,0,0);line.AddVertexAt(1,new Autodesk.AutoCAD.Geometry.Point2d(segment.EndPoint.X,segment.EndPoint.Y),0,0,0);line.Elevation=segment.StartPoint.Z;segment.Dispose();line.LayerId=layerId;line.ColorIndex=256;line.LineWeight=LineWeight.ByLayer;space.AppendEntity(line);tr.AddNewlyCreatedDBObject(line,true);lines++;}region.LayerId=layerId;region.ColorIndex=256;region.LineWeight=LineWeight.ByLayer;space.AppendEntity(region);tr.AddNewlyCreatedDBObject(region,true);}boundaries++;if(temporary)p.Dispose();}catch(System.Exception ex){if(temporary)p?.Dispose();skipped++;ed.WriteMessage("\nVDNG: Bỏ qua Boundary "+id.Handle+" — "+ex.Message);}}tr.Commit();}ed.WriteMessage("\nVDNG: Xử lý "+boundaries+" Boundary, bỏ qua "+skipped+", tạo "+lines+" đoạn dây và đường nối biên trong.");}static Polyline CircleBoundary(Circle circle){var p=new Polyline(4);double r=circle.Radius,x=circle.Center.X,y=circle.Center.Y,bulge=Math.Tan(Math.PI/8);p.AddVertexAt(0,new Autodesk.AutoCAD.Geometry.Point2d(x+r,y),bulge,0,0);p.AddVertexAt(1,new Autodesk.AutoCAD.Geometry.Point2d(x,y+r),bulge,0,0);p.AddVertexAt(2,new Autodesk.AutoCAD.Geometry.Point2d(x-r,y),bulge,0,0);p.AddVertexAt(3,new Autodesk.AutoCAD.Geometry.Point2d(x,y-r),bulge,0,0);p.Closed=true;return p;}}
}
